import{_ as l,a8 as a,o as _,c as d,a as r,a3 as o,K as t,L as h,au as c}from"./chunks/framework.DWNOz7zu.js";import"./chunks/theme.CtRhYxUW.js";const V=JSON.parse('{"title":"三分钟了解「自适应」与「响应式」布局🔗","description":"","frontmatter":{"tags":["开发/前端","艺术/设计"]},"headers":[],"relativePath":"zh-CN/笔记/🛠️ 开发/「自适应」与「响应式」布局.md","filePath":"zh-CN/笔记/🛠️ 开发/「自适应」与「响应式」布局.md"}'),m={name:"zh-CN/笔记/🛠️ 开发/「自适应」与「响应式」布局.md"},b={id:"三分钟了解「自适应」与「响应式」布局🔗",tabindex:"-1"};function f(g,e,N,P,C,u){const n=a("VPNolebaseInlineLinkPreview"),s=a("NolebasePageProperties"),p=a("NolebaseGitContributors"),i=a("NolebaseGitChangelog");return _(),d("div",null,[r("h1",b,[e[1]||(e[1]=o("三分钟了解「自适应」与「响应式」布局",-1)),t(n,{href:"https://zhuanlan.zhihu.com/p/157443159",target:"_blank",rel:"noreferrer"},{default:h(()=>[...e[0]||(e[0]=[o("🔗",-1)])]),_:1}),e[2]||(e[2]=o()),e[3]||(e[3]=r("a",{class:"header-anchor",href:"#三分钟了解「自适应」与「响应式」布局🔗","aria-label":"Permalink to “三分钟了解「自适应」与「响应式」布局🔗”"},"​",-1))]),t(s),e[4]||(e[4]=c('<p>自适应与响应式布局，别再傻傻分不清，本文作者从以下几点详细介绍响应式和自适应有什么区别。</p><h2 id="自适应布局" tabindex="-1">自适应布局 <a class="header-anchor" href="#自适应布局" aria-label="Permalink to “自适应布局”">​</a></h2><p>自适应布局是网页内容根据设备的不同而进行适应；</p><p>通过检测视口分辨率，来判断当前访问的设备是pc端、平板还是手机，从而请求服务层，返回不同的页面；</p><p>需要根据不同使用场景开发多套界面。</p><p><img src="https://pic4.zhimg.com/80/v2-3520dfbf13d5a7af8258ff443eab7737_720w.jpg" alt=""></p><h3 id="技术原理" tabindex="-1">技术原理 <a class="header-anchor" href="#技术原理" aria-label="Permalink to “技术原理”">​</a></h3><p>分别为不同的屏幕分辨率定义布局，即创建多个静态布局，每个静态布局对应一个屏幕分辨率范围。改变屏幕分辨率可以切换不同的静态局部（页面元素位置发生改变），但在每个静态布局中，页面元素不随窗口大小的调整发生变化。</p><p><strong>布局特点：</strong>屏幕分辨率变化时，页面里面元素的位置会变化，而大小不会变化。</p><p><strong>设计方法：</strong>使用媒体查询给不同尺寸和介质的设备切换不同的样式，在同一个设备下实际还是固定的布局。</p><h2 id="响应式布局" tabindex="-1">响应式布局 <a class="header-anchor" href="#响应式布局" aria-label="Permalink to “响应式布局”">​</a></h2><p>响应式布局是网页的布局针对屏幕大小的尺寸而进行响应；</p><p>通过检测视口分辨率，针对不同客户端在客户端做代码处理，来展现不同的布局和内容；</p><p>只需要开发一套界面即可适用于所有尺寸及终端。</p><p><img src="https://pic1.zhimg.com/80/v2-a88758f587c4f292b2f69e043ad1ebb4_720w.jpg" alt=""></p><h3 id="技术原理-1" tabindex="-1">技术原理 <a class="header-anchor" href="#技术原理-1" aria-label="Permalink to “技术原理”">​</a></h3><p>糅合了流式布局+弹性布局，再搭配媒体查询技术使用。</p><p>分别为不同的屏幕分辨率定义布局，同时，在每个布局中，应用流式布局的理念，使页面元素宽度随着窗口调整而自动适配。</p><p>即：创建多个流体式布局，分别对应一个屏幕分辨率范围。可以把响应式布局看作是流式布局和自适应布局设计理念的融合。</p><p><strong>布局特点：</strong>每个屏幕分辨率下面会有一个布局样式，即元素位置和大小都会变。</p><p><strong>设计方法：</strong>媒体查询+流式布局。</p><p>通常使用媒体查询和网格系统配合相对布局单位进行布局，实际上就是综合响应式、流动等技术通过 CSS 给单一网页不同设备返回不同样式的技术统称。</p>',22)),t(p),t(i)])}const v=l(m,[["render",f]]);export{V as __pageData,v as default};
